func ForwardCookies_Buggy(ctx context.Context, req *http.Request) metadata.MD {
	md := metadata.MD{}
	for _, key := range []string{"flipt_client_state", "flipt_client_token"} {
		if cookie, err := req.Cookie(key); err == nil {
			// BUG: This always uses "flipt_client_state" instead of 'key'
			md["flipt_client_state"] = []string{cookie.Value}
		}
	}
	return md
}

// TestRegression_CookieTokenNotExtracted demonstrates that the ForwardCookies function
// has a bug where it doesn't properly forward the flipt_client_token cookie to gRPC metadata.
// This prevents browser-based sessions from working since HTTP cookies are not extracted
// and forwarded correctly.
func TestRegression_CookieTokenNotExtracted(t *testing.T) {
	const (
		clientToken = "test_token_12345"
		stateCookie = "state_cookie_value"
	)

	// Create a test HTTP request with both state and client token cookies
	req := httptest.NewRequest("GET", "http://localhost/api/v1/flags", nil)
	req.AddCookie(&http.Cookie{
		Name:  "flipt_client_state",
		Value: stateCookie,
	})
	req.AddCookie(&http.Cookie{
		Name:  "flipt_client_token",
		Value: clientToken,
	})

	// Call ForwardCookies to convert HTTP cookies to gRPC metadata
	md := ForwardCookies_Buggy(context.Background(), req)

	// BUG: The current implementation doesn't properly forward cookies
	// Line 49 of http.go always uses "flipt_client_state" as the key,
	// even when processing the "flipt_client_token" cookie

	// Check the metadata structure
	stateValues := md.Get("flipt_client_state")
	tokenValues := md.Get("flipt_client_token")

	if len(md) == 0 {
		t.Error("REGRESSION: ForwardCookies returned empty metadata")
		return
	}

	// The bug causes the token cookie value to overwrite the state value
	// because both are written to the same "flipt_client_state" key
	if len(stateValues) > 0 {
		t.Logf("Value at flipt_client_state: %v", stateValues[0])

		// Due to the bug, this will contain the token value (the last one processed)
		// instead of the state value
		if stateValues[0] == clientToken {
			t.Log("REGRESSION: Token value overwrote state value due to bug - both keys write to same metadata entry")
		} else if stateValues[0] == stateCookie {
			t.Log("State value is correct, but token value is missing")
		}
	}

	if len(tokenValues) == 0 {
		t.Error("REGRESSION: flipt_client_token key not found in metadata - tokens cannot be extracted from cookies")
	}

	// The expected behavior:
	// - md["flipt_client_state"] should contain stateCookie
	// - md["flipt_client_token"] should contain clientToken
	// But due to the bug, the second key never gets properly set
}

// TestRegression_ForwardCookiesBugDetails demonstrates the exact bug in the ForwardCookies function.
// The function iterates over cookie keys (stateCookieKey and tokenCookieKey) but always
// sets the metadata using stateCookieKey, overwriting entries instead of properly forwarding them.
func TestRegression_ForwardCookiesBugDetails(t *testing.T) {
	const (
		stateCookieValue = "state123"
		tokenCookieValue = "token456"
	)

	req := httptest.NewRequest("GET", "http://localhost/test", nil)
	req.AddCookie(&http.Cookie{
		Name:  "flipt_client_state",
		Value: stateCookieValue,
	})
	req.AddCookie(&http.Cookie{
		Name:  "flipt_client_token",
		Value: tokenCookieValue,
	})

	md := ForwardCookies_Buggy(context.Background(), req)

	// When ForwardCookies processes cookies, it:
	// 1. Iterates through [stateCookieKey, tokenCookieKey]
	// 2. Extracts each cookie value
	// 3. BUT: Always sets md[stateCookieKey] regardless of which key is being processed

	// This means:
	// - When processing stateCookieKey, it sets md["flipt_client_state"] = stateCookieValue
	// - When processing tokenCookieKey, it sets md["flipt_client_state"] = tokenCookieValue (WRONG!)
	// The tokenCookieKey value overwrites the stateCookieKey entry due to the bug

	// Due to the bug, we expect that md will have wrong keys/values:
	stateValues := md.Get("flipt_client_state")

	if len(stateValues) > 0 {
		// This might contain the token value instead of the state value due to the bug
		// The last value would be from processing tokenCookieKey
		t.Logf("Value at flipt_client_state key: %v", stateValues[0])
		if stateValues[0] == tokenCookieValue {
			t.Error("REGRESSION: Token cookie overwrote state cookie in metadata due to bug in ForwardCookies")
		}
	}

	// Try to access the metadata using the correct key for token
	tokenValues := md.Get("flipt_client_token")
	if len(tokenValues) == 0 {
		t.Error("REGRESSION: No flipt_client_token key in metadata - ForwardCookies bug prevents proper forwarding")
	}

	// The expected behavior would be:
	// - md["grpcgateway-cookie"] = ["flipt_client_state=state123; flipt_client_token=token456"]
	// OR individual entries:
	// - md["flipt_client_state"] = ["state123"]
	// - md["flipt_client_token"] = ["token456"]
	// But the current implementation doesn't properly forward to the gRPC middleware's expected format
}

// TestRegression_ServerAuthenticationSkipNotConfigured demonstrates that while servers
// can implement the SkipsAuthenticationServer interface, there's no mechanism to register
// them with the authentication middleware to actually skip authentication.
// This means even "public" servers that should not require authentication still have
// authentication enforced on them.
func TestRegression_ServerAuthenticationSkipNotConfigured(t *testing.T) {
	// The SkipsAuthenticationServer interface exists and is implemented by public.Server
	// but in internal/cmd/authn.go, when authenticationGRPC() is called, the
	// WithServerSkipsAuthentication option is never used to register servers.

	// This means:
	// 1. Public authentication methods (like ListAuthenticationMethods) should not require auth
	// 2. But there's no mechanism to bypass the AuthenticationRequiredInterceptor
	// 3. The skipped() function in middleware.go checks if a server implements
	//    SkipsAuthenticationServer, but servers are never registered with this option

	// Verify that WithServerSkipsAuthentication option exists
	var opts []interface{}
	// This function exists but is never called in the registration code
	// opts = append(opts, grpc_middleware.WithServerSkipsAuthentication(publicServer))

	// Without calling WithServerSkipsAuthentication during setup, the middleware has no way
	// to know which servers should skip authentication, and the skipped() function will
	// always return false for the skipped servers slice check.

	// The expected behavior would be:
	// 1. Public servers implement SkipsAuthenticationServer
	// 2. They should be registered with WithServerSkipsAuthentication during middleware setup
	// 3. The middleware's skipped() function should check the interface AND the registered list

	// But currently step 2 is missing, so all servers require authentication

	t.Log("REGRESSION: Server-level authentication skip mechanism exists but is not configured")
	t.Log("Public servers implement SkipsAuthenticationServer interface")
	t.Log("But WithServerSkipsAuthentication is never called during middleware setup")
	t.Log("This means public servers are incorrectly forced to require authentication")
}

